python3 -c "
import json
import sys

# Read files
with open('schema.json', 'r') as f:
    schema = json.load(f)
with open('profile.json', 'r') as f:
    profile = json.load(f)

# Try to use jsonschema if available
try:
    from jsonschema import validate
    validate(profile, schema)
    print('✓ profile.json validates against schema.json')
    print('Data:')
    print(json.dumps(profile, indent=2))
except ImportError:
    # Manual validation
    def validate_manual(data, schema):
        errors = []

        # Check required top-level keys
        required = schema.get('required', [])
        for key in required:
            if key not in data:
                errors.append(f'Missing required key: {key}')

        # Check additionalProperties at top level
        if not schema.get('additionalProperties', True):
            for key in data:
                if key not in schema.get('properties', {}):
                    errors.append(f'Additional property not allowed: {key}')

        # Validate id
        if 'id' in data:
            id_schema = schema['properties'].get('id', {})
            if not isinstance(data['id'], str):
                errors.append('id must be a string')
            elif 'pattern' in id_schema:
                import re
                if not re.match(id_schema['pattern'], data['id']):
                    errors.append(f'id does not match pattern: {id_schema[\"pattern\"]}')

        # Validate owner
        if 'owner' in data:
            owner = data['owner']
            owner_schema = schema['properties'].get('owner', {})

            # Check required fields in owner
            for key in owner_schema.get('required', []):
                if key not in owner:
                    errors.append(f'Missing required key in owner: {key}')

            # Check additionalProperties in owner
            if not owner_schema.get('additionalProperties', True):
                for key in owner:
                    if key not in owner_schema.get('properties', {}):
                        errors.append(f'Additional property not allowed in owner: {key}')

            # Validate owner fields
            if 'name' in owner:
                name_schema = owner_schema['properties'].get('name', {})
                if not isinstance(owner['name'], str):
                    errors.append('owner.name must be a string')
                elif 'minLength' in name_schema and len(owner['name']) < name_schema['minLength']:
                    errors.append(f'owner.name is too short (minLength: {name_schema[\"minLength\"]})')

            if 'team' in owner:
                team_schema = owner_schema['properties'].get('team', {})
                if 'enum' in team_schema and owner['team'] not in team_schema['enum']:
                    errors.append(f'owner.team must be one of: {team_schema[\"enum\"]}')

        return errors

    errors = validate_manual(profile, schema)
    if errors:
        print('✗ Validation failed:')
        for error in errors:
            print(f'  - {error}')
        sys.exit(1)
    else:
        print('✓ profile.json validates against schema.json')
        print('Data:')
        print(json.dumps(profile, indent=2))
"

